record.field:
request = False
pool_for_create = False

for rec in records:
    if rec.x_intake_phase != 'pooling':
        continue
    if rec.x_chairman_decision not in ('approved', 'on_hold'):
        continue

    existing_request = False
    for item in rec.x_conversion_request_ids:
        if item.x_state in ('in_progress', 'approved'):
            existing_request = item
            break
    if existing_request:
        request = existing_request
        rec.sudo().write({'x_intake_phase': 'conversion'})
        rec.message_post(body='Opened existing conversion request: %s' % (request.display_name,))
    else:
        pool_for_create = rec

if len(records) == 1:
    if request:
        action = {
            'type': 'ir.actions.act_window',
            'name': 'Conversion Request',
            'res_model': 'x_hr.pool_conversion_request',
            'view_mode': 'form',
            'res_id': request.id,
            'target': 'current',
        }
    elif pool_for_create:
        pool_label = pool_for_create.x_name or pool_for_create.x_intake_reference or pool_for_create.display_name or 'Conversion Request'
        action = {
            'type': 'ir.actions.act_window',
            'name': 'Conversion Request',
            'res_model': 'x_hr.pool_conversion_request',
            'view_mode': 'form',
            'target': 'current',
            'context': {
                'default_x_name': pool_label,
                'default_x_pool_id': pool_for_create.id,
                'default_x_state': 'in_progress',
                'default_x_requested_by': env.user.id,
            },
        }

for req in records:
    if req.x_state != 'in_progress':
        continue
    if not req.x_job_id:
        continue

    pool = req.x_pool_id.sudo()
    applicant = pool.x_applicant_id or req.x_applicant_id
    if not applicant:
        Applicant = env['hr.applicant'].sudo()
        applicant_vals = {'job_id': req.x_job_id.id}
        candidate_label = pool.x_name or pool.x_intake_reference or req.x_name or pool.display_name or 'Converted Candidate'
        fields_map = Applicant._fields

        if 'name' in fields_map:
            applicant_vals['name'] = candidate_label
        if 'partner_name' in fields_map:
            applicant_vals['partner_name'] = candidate_label
        if 'email_from' in fields_map and pool.x_email:
            applicant_vals['email_from'] = pool.x_email
        if 'partner_phone' in fields_map and pool.x_phone:
            applicant_vals['partner_phone'] = pool.x_phone
        if 'x_national_id' in fields_map and pool.x_national_id:
            applicant_vals['x_national_id'] = pool.x_national_id
        if 'x_gender' in fields_map and pool.x_gender:
            applicant_vals['x_gender'] = pool.x_gender
        if 'company_id' in fields_map and req.x_job_id.company_id:
            applicant_vals['company_id'] = req.x_job_id.company_id.id
        if 'department_id' in fields_map and req.x_job_id.department_id:
            applicant_vals['department_id'] = req.x_job_id.department_id.id
        if 'description' in fields_map:
            applicant_vals['description'] = '\n\n'.join([
                part for part in [
                    pool.x_commitments_description or '',
                    req.x_notes or '',
                ] if part
            ])

        applicant = Applicant.create(applicant_vals)

    req.sudo().write({
        'x_state': 'approved',
        'x_decided_by': env.user.id,
        'x_applicant_id': applicant.id,
    })
    pool.write({
        'x_intake_phase': 'converted',
        'x_chairman_decision': 'approved',
        'x_conversion_job_id': req.x_job_id.id,
        'x_applicant_id': applicant.id,
    })
    req.message_post(body='Conversion request approved.')
    pool.message_post(body='Pool record converted to applicant.')

for req in records:
    if req.x_state != 'in_progress':
        continue

    pool = req.x_pool_id.sudo()
    req.sudo().write({
        'x_state': 'rejected',
        'x_decided_by': env.user.id,
    })
    pool.write({
        'x_intake_phase': 'pooling',
        'x_chairman_decision': 'approved',
    })
    req.message_post(body='Conversion request rejected.')
    pool.message_post(body='Conversion request rejected; pool returned to pooling and remains chairman-approved.')
